import requests
import re

def Sitedossier_Api(domain):
    try:
        url = f"http://www.sitedossier.com/parentdomain/{domain}"
        response = requests.get(url)
        rest = response.text
        result = {r.strip('.') for r in re.findall('<a href="/site/(.*?)">', rest) if domain in r}
    except Exception as e:
        result = set()

    print(f'[+ Sitedossier API] Sitedossier接口 : {domain} 捕获子域名总数 : {len(result)}')
    return list(result)

