def _calculate_fip_pfs_differences(self, ovn_rtr_lb_pfs, db_pfs):
    to_add_or_update = set()
    ovn_pfs = utils.parse_ovn_lb_port_forwarding(ovn_rtr_lb_pfs)

    # Map the db_pfs by their floatingip_id and protocol using set comprehension
    db_mapped_pfs = {}
    for db_pf in db_pfs:
        for pf in self._unroll_port_forwarding(db_pf):
            fip_id = pf.get('floatingip_id')
            protocol = self.l3_plugin.port_forwarding.ovn_lb_protocol(
                pf.get('protocol'))
            db_vip = "{}:{} {}:{}".format(
                pf.get('floating_ip_address'), pf.get('external_port'),
                pf.get('internal_ip_address'), pf.get('internal_port'))

            if fip_id not in db_mapped_pfs:
                db_mapped_pfs[fip_id] = {}

            db_mapped_pfs[fip_id].setdefault(protocol, set()).add(db_vip)

    # Detect things to add or update based on differences between ovn_pfs and db_mapped_pfs
    for fip_id, db_fip_dict in db_mapped_pfs.items():
        ovn_fip_dict = ovn_pfs.get(fip_id, {})

        # Check if there are missing protocols or mismatched VIPs
        if len(db_fip_dict) != len(ovn_fip_dict) or any(
            db_fip_dict[protocol] != ovn_fip_dict.get(protocol)
            for protocol in db_fip_dict
        ):
            to_add_or_update.add(fip_id)

    # Set comprehension to collect FIP IDs in ovn_pfs but not in db_pfs
    db_fip_ids = {pf.get('floatingip_id') for db_pf in db_pfs for pf in self._unroll_port_forwarding(db_pf)}
    to_remove = [fip_id for fip_id in ovn_pfs if fip_id not in db_fip_ids]

    return list(to_add_or_update), to_remove

