def check_bad_submessage(self, result, name, data, src_data, flags):
    """Detect any bad sub-message selectors."""
    if "-submessage_selectors" in flags:
        return

    if (
        src_data
        and "select" in data["types"]
        and "select" in src_data["types"]
        and "choices" in data
        and "choices" in src_data
    ):
        choices = data["choices"]
        src_choices = src_data["choices"]

        # Using set comprehension to create set of bad choices
        bad = {selector for selector in choices if selector not in src_choices}

        if bad:
            result["bad_submessage"].append([name, bad])

