def get_triggered_stages(self):
    # Use set comprehension to find the stages where the method is overridden
    trigger_stages = {stage for stage in Hook.stages if is_method_overridden(stage, Hook, self)}

    # Dictionary to map methods to multi-stage triggers for updates
    method_stages_map = {
        'before_epoch': ['before_train_epoch', 'before_val_epoch'],
        'after_epoch': ['after_train_epoch', 'after_val_epoch'],
        'before_iter': ['before_train_iter', 'before_val_iter'],
        'after_iter': ['after_train_iter', 'after_val_iter'],
    }

    # Use set comprehension with update for the matching method overrides
    for method, map_stages in method_stages_map.items():
        if is_method_overridden(method, Hook, self):
            trigger_stages.update(map_stages)

    return [stage for stage in Hook.stages if stage in trigger_stages]

