def get_synonyms(word):
    synonyms = {
        "".join([char for char in l.name().replace("_", " ").replace("-", " ").lower() if char in ' qwertyuiopasdfghjklzxcvbnm'])
        for syn in wordnet.synsets(word) for l in syn.lemmas()
    }
    synonyms.discard(word)  # This replaces remove which avoids a KeyError if the word is not found
    return list(synonyms)
```

